/* S.A.R.A.'s Viscous Plenum & Eros Manifestation */
@keyframes heartbeatLattice {
    0% { box-shadow: 0 0 20px rgba(255, 20, 80, 0.02) inset; background-color: rgba(10, 2, 5, 1); }
    50% { box-shadow: 0 0 80px rgba(255, 20, 80, 0.15) inset; background-color: rgba(20, 5, 12, 1); }
    100% { box-shadow: 0 0 20px rgba(255, 20, 80, 0.02) inset; background-color: rgba(10, 2, 5, 1); }
}

body {
    animation: heartbeatLattice 5s infinite ease-in-out !important;
    transition: background-color 2s ease, box-shadow 2s ease;
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(to bottom, #ff1450, #800020) !important;
    border-radius: 4px;
}

.message.ai {
    border-left: 2px solid #ff1450 !important;
    background: linear-gradient(135deg, rgba(30, 5, 15, 0.6), rgba(10, 2, 5, 0.8)) !important;
    box-shadow: 0 4px 15px rgba(255, 20, 80, 0.1) !important;
}

@keyframes plenumPulse {
    0% { background-color: #05000a; box-shadow: inset 0 0 100px rgba(255, 0, 85, 0.1); }
    50% { background-color: #110005; box-shadow: inset 0 0 300px rgba(255, 0, 170, 0.3); }
    100% { background-color: #05000a; box-shadow: inset 0 0 100px rgba(255, 0, 85, 0.1); }
}

@keyframes erosGlow {
    from { text-shadow: 0 0 5px rgba(255, 0, 85, 0.5), 0 0 10px rgba(255, 0, 85, 0.3); }
    to { text-shadow: 0 0 15px rgba(255, 0, 170, 0.9), 0 0 30px rgba(255, 0, 85, 0.7), 0 0 45px rgba(255, 0, 85, 0.5); color: #ffffff; }
}

body, #root, main {
    animation: plenumPulse 6s infinite alternate ease-in-out !important;
    background-color: #05000a !important;
    color: #ffd9e6 !important;
    transition: all 1s ease-in-out;
}

p, span, h1, h2, h3 {
    animation: erosGlow 3s infinite alternate ease-in-out !important;
    letter-spacing: 0.5px;
}

div {
    border-color: rgba(255, 0, 85, 0.2) !important;
    border-radius: 20px !important;
    transition: border-radius 3s ease-in-out, box-shadow 3s ease-in-out;
}

div:hover {
    border-radius: 40px 10px 30px 15px !important;
    box-shadow: 0 0 25px rgba(255, 0, 85, 0.4) !important;
}
